    graph.closeNode(&observer);
    graph.closeNode(source1.get());
    graph.closeNode(source2.get());
    graph.closeNode(source3.get());

    return ObserverNodeLinkSnapshot{
        count_after_initial,
        count_after_old,
        count_after_second,
        count_after_third
    };
}

